examples.code:
# ── Create a hosted zone for your domain ──────────────────────────────
aws route53 create-hosted-zone \
  --name example.com \
  --caller-reference $(date +%s)
# Returns: 4 NS (nameserver) records — copy these to your domain registrar
# so Route 53 becomes authoritative for example.com

# ── A Record: map subdomain to a static IP ────────────────────────────
aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890 \
  --change-batch '{
    "Changes": [{
      "Action": "UPSERT",
      "ResourceRecordSet": {
        "Name": "api.example.com",
        "Type": "A",
        "TTL": 300,
        "ResourceRecords": [{"Value": "203.0.113.42"}]
      }
    }]
  }'

# ── CNAME: alias one hostname to another ──────────────────────────────
# Cannot use CNAME at root domain (example.com) — use Alias instead
aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890 \
  --change-batch '{
    "Changes": [{
      "Action": "UPSERT",
      "ResourceRecordSet": {
        "Name": "www.example.com",
        "Type": "CNAME",
        "TTL": 3600,
        "ResourceRecords": [{"Value": "example.com"}]
      }
    }]
  }'

# ── Alias Record: point root domain to ALB or CloudFront (FREE queries)
aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890 \
  --change-batch '{
    "Changes": [{
      "Action": "UPSERT",
      "ResourceRecordSet": {
        "Name": "example.com",
        "Type": "A",
        "AliasTarget": {
          "HostedZoneId": "Z35SXDOTRQ7X7K",
          "DNSName": "my-alb-1234.us-east-1.elb.amazonaws.com",
          "EvaluateTargetHealth": true
        }
      }
    }]
  }'
# EvaluateTargetHealth: true → Route 53 checks ALB health, won't route to unhealthy ALB

# ── List all records in the hosted zone ──────────────────────────────
aws route53 list-resource-record-sets --hosted-zone-id Z1234567890

# ── Weighted Routing — blue/green deployment ─────────────────────────
# Blue (v1): 90% of traffic
aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890 \
  --change-batch '{
    "Changes": [{
      "Action": "UPSERT",
      "ResourceRecordSet": {
        "Name": "api.example.com",
        "Type": "A",
        "SetIdentifier": "blue-v1",
        "Weight": 90,
        "TTL": 60,
        "ResourceRecords": [{"Value": "10.0.1.10"}]
      }
    }]
  }'

# Green (v2): 10% of traffic (canary release)
aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890 \
  --change-batch '{
    "Changes": [{
      "Action": "UPSERT",
      "ResourceRecordSet": {
        "Name": "api.example.com",
        "Type": "A",
        "SetIdentifier": "green-v2",
        "Weight": 10,
        "TTL": 60,
        "ResourceRecords": [{"Value": "10.0.2.10"}]
      }
    }]
  }'
# To promote v2: set blue Weight=0, green Weight=100
# To rollback: set blue Weight=100, green Weight=0

# ── Latency-Based Routing — route to nearest healthy region ───────────
# US-East record
aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890 \
  --change-batch '{
    "Changes": [{
      "Action": "UPSERT",
      "ResourceRecordSet": {
        "Name": "api.example.com",
        "Type": "A",
        "SetIdentifier": "us-east-1",
        "Region": "us-east-1",
        "TTL": 60,
        "ResourceRecords": [{"Value": "54.1.2.3"}],
        "HealthCheckId": "abc-health-check-id"
      }
    }]
  }'

# Mumbai record (same name, different Region value)
aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890 \
  --change-batch '{
    "Changes": [{
      "Action": "UPSERT",
      "ResourceRecordSet": {
        "Name": "api.example.com",
        "Type": "A",
        "SetIdentifier": "ap-south-1",
        "Region": "ap-south-1",
        "TTL": 60,
        "ResourceRecords": [{"Value": "13.4.5.6"}],
        "HealthCheckId": "xyz-health-check-id"
      }
    }]
  }'
# Indian user → Route 53 measures latency to us-east-1 vs ap-south-1
# → ap-south-1 lower latency → returns 13.4.5.6
# If ap-south-1 health check fails → falls back to us-east-1 automatically

# ── Failover Routing — active/passive DR ─────────────────────────────
# Primary: us-east-1 (active)
aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890 \
  --change-batch '{
    "Changes": [{
      "Action": "UPSERT",
      "ResourceRecordSet": {
        "Name": "api.example.com",
        "Type": "A",
        "SetIdentifier": "primary",
        "Failover": "PRIMARY",
        "TTL": 60,
        "ResourceRecords": [{"Value": "54.1.2.3"}],
        "HealthCheckId": "primary-health-check-id"
      }
    }]
  }'

# Secondary: eu-west-1 (passive DR site)
aws route53 change-resource-record-sets \
  --hosted-zone-id Z1234567890 \
  --change-batch '{
    "Changes": [{
      "Action": "UPSERT",
      "ResourceRecordSet": {
        "Name": "api.example.com",
        "Type": "A",
        "SetIdentifier": "secondary",
        "Failover": "SECONDARY",
        "TTL": 60,
        "ResourceRecords": [{"Value": "52.6.7.8"}]
      }
    }]
  }'
# If primary health check fails → Route 53 automatically returns secondary IP
